    '["Силовые повороты руки наружу и внутрь в нейтрали и в отведении, упражнение «полный стакан» (большой палец вверх)","Повороты руки наружу лёжа на боку, тяги в наклоне, отжимания с выведением лопатки вперёд","Диагональные движения и упражнения на удержание стабильного положения плеча","Силовая работа бицепса, поворота предплечья наружу и внутрь с постепенной прогрессией","Упражнения с опорой (закрытая цепь), бег","Возврат к силовой работе с лёгкими весами и большим числом повторений, избегая жима из-за головы и жима широким хватом"]',
    '["Тренировки должны быть без боли","Стойкое усиление симптомов — повод пересмотреть нагрузку"]',
    '["Чередуйте силовые и восстановительные дни","Прибавляйте нагрузку постепенно, особенно на бицепс","Следите за реакцией плеча на следующий день"]',
    '["Возврат боли в зоне тенодеза при нагрузке","Деформация контура бицепса","Эпизод острой боли в плече"]',
    '[{"q":"Почему так много повторений и так мало веса?","a":"Большое число повторений с лёгким весом наращивает силу и выносливость мягко, без резких пиков нагрузки на бицепс и место фиксации. Это безопасный способ вернуть силу."},{"q":"Почему пока нельзя жим из-за головы?","a":"Жим из-за головы и широким хватом даёт большую нагрузку на переднюю часть плеча и бицепс. К таким движениям возвращаются позже и постепенно."}]'
),
(
    'shoulder_biceps_tenodesis', 5,
    'Возврат к спорту и полной активности',
    'От 12 недель',
    '12-16',
    'Финальный этап. Плечо и бицепс сильные и подвижные — готовим их к вашим реальным задачам: работе, спорту, нагрузкам. Решение о возврате к полной и контактной активности принимается индивидуально и только с допуском врача. Единого срока нет — спешка повышает риск повторной травмы.',
    '["Наращивать силу и мощность без компенсаций","Вернуться к работе и спорту","Сохранять полный безболезненный объём движений","Хороший контроль передней части плеча"]',
    '["Допуск к полной и контактной активности — только после очной оценки и разрешения врача","Нагрузку наращивать постепенно","Единого числового срока возврата к спорту нет — решает куратор вместе с врачом (в литературе диапазон допуска 12–36 недель)"]',
    '["Сила оперированной руки не менее 90% от здоровой стороны (по динамометрии)","Норма по полевым тестам на устойчивость и силу плеча (где применимо)","Низкий уровень жалоб по опроснику самооценки руки","Безболезненные контролируемые быстрые и спорт-специфичные движения, очный допуск куратора или врача"]',
    'trophy', '#EC4899', '#FFF9E6',
    'Возврат к спорту по силе и допуску врача',
    '["Прыжково-бросковые упражнения: от движений ниже плеча к работе над головой, от двух рук к одной","Интервальные программы возврата (броски, плавание)","Прогрессивный возврат к силовой программе с акцентом на крупные мышцы","Жим и тяга вверх — постепенно, бережно к передней части плеча"]',
    '["Цель — полный безболезненный объём при быстрых и спорт-специфичных движениях","Боль или нестабильность при быстрых движениях — повод сбавить и сообщить куратору"]',
    '["Полноценная разминка перед каждой нагрузкой","Возвращайтесь к спорту постепенно, без рывков","Прислушивайтесь к плечу на следующий день после нагрузки"]',
    '["Боль или нестабильность при высокоскоростных движениях","Деформация контура бицепса","Возврат боли в борозде на передней поверхности плеча"]',
    '[{"q":"Когда можно вернуться к спорту?","a":"Возврат решается индивидуально и только с допуском врача — учитывают силу (не меньше 90% от здоровой руки), полный объём движений и срок после операции. Единого числа нет, в литературе диапазон 12–36 недель."},{"q":"Нужно ли продолжать упражнения после возврата к нагрузкам?","a":"Да. Поддерживающая программа сохраняет силу плеча и бицепса и снижает риск повторной проблемы. Это надолго."}]'
)
ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода shoulder_biceps_tenodesis
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фаза 0 (prehab) — без structured-критериев, в WITH НЕ включена.
--    Фазы 1–5 включены (терминальная фаза 5 несёт критерии возврата к спорту/полной активности).
--    У протокола НЕТ measurement-критериев: источник не задаёт критериев перехода по боли/ВАШ
--    напрямую → боль/болезненность идёт как self_report; числовые пороги (градусы, MMT, %) →
--    instructor_check с порогом в тексте label (куратор очно).
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (защита и пассивные движения → активные движения)
  (1, 'full_passive_elbow_p1',   'Полный пассивный объём движений локтя (сгибание и разгибание), как на здоровой стороне', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'full_passive_forearm_p1', 'Полный пассивный поворот предплечья наружу и внутрь (супинация и пронация)',              'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'er_within_40_p1',         'Поворот руки наружу удавалось держать в пределах около 40° без боли; пассивный объём плеча полный в разрешённых границах', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'pain_reduced_p1',         'Боль уменьшилась по сравнению с первыми днями после операции',                           'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Уменьшилась ли боль по сравнению с первыми днями после операции?', 'Сравните с тем, как было сразу после операции', 40::smallint, TRUE),
  (1, 'wound_healed_p1',         'Рана зажила, нет признаков инфекции и расхождения',                                      'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),
  (1, 'pain_controlled_p1',      'Боль под контролем без необходимости держать руку обездвиженной в покое',                'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 60::smallint, FALSE),

  -- Фаза 2 → Фаза 3 (активные движения → начальное укрепление)
  (2, 'full_active_shoulder_p2', 'Полный безболезненный активный объём движений плеча во всех направлениях',                'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'full_active_elbow_p2',    'Полный безболезненный активный объём движений локтя (сгибание и разгибание)',             'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'full_active_forearm_p2',  'Полный безболезненный активный поворот предплечья наружу и внутрь',                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'scapular_control_p2',     'Правильная осанка и слаженная работа лопатки при активных движениях (оценка куратора)',  'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, FALSE),
  (2, 'adl_waist_level_p2',      'Бытовые действия на уровне пояса получаются без боли',                                   'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Получается выполнять бытовые действия на уровне пояса без боли?', 'Например, поесть, одеться, набрать текст', 50::smallint, TRUE),

  -- Фаза 3 → Фаза 4 (начальное укрепление → продвинутое укрепление)
  (3, 'full_active_rom_p3',      'Полный активный объём движений плеча и локтя со слаженной работой лопатки',               'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'strengthen_tolerance_p3', 'Хорошая переносимость начального укрепления без усиления симптомов (оценка куратора)',    'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'no_next_day_pain_p3',     'Нет боли и болезненности на следующий день после укрепляющих упражнений',                'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Нет ли у вас боли или болезненности на следующий день после укрепляющих упражнений?', 'Оцените по нескольким занятиям с лентой и лёгкими весами', 30::smallint, TRUE),
  (3, 'no_scapular_shrug_p3',    'Нет компенсаторного подъёма лопатки к уху при подъёме руки (оценка куратора)',           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, FALSE),

  -- Фаза 4 → Фаза 5 (продвинутое укрепление → возврат к спорту)
  (4, 'strength_5_of_5_p4',      'Сила плеча и локтя на уровне здоровой стороны (по оценке куратора — 5 из 5)',             'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'full_active_shoulder_p4', 'Полный безболезненный активный объём движений плеча во всех направлениях',                'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'strengthen_tolerance_p4', 'Хорошая переносимость укрепления без усиления симптомов (оценка куратора)',               'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (4, 'chest_level_confident_p4','Уверенное безболезненное выполнение нагрузок на уровне груди и выше',                     'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Уверенно ли вы выполняете нагрузки на уровне груди и выше без боли?', 'Оцените по последним силовым занятиям', 40::smallint, TRUE),

  -- Фаза 5 (терминальная) — критерии возврата к спорту / полной активности
  (5, 'strength_90_pct_p5',      'Сила оперированной руки не менее 90% от здоровой стороны (по динамометрии)',              'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (5, 'field_tests_normal_p5',   'Норма по полевым тестам на устойчивость и силу плеча (где применимо)',                    'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, FALSE),
  (5, 'questionnaire_low_p5',    'Низкий уровень жалоб по опроснику самооценки руки',                                      'self_report',      NULL, NULL, NULL, NULL, NULL, 14::smallint, 'Опросник самооценки руки показывает низкий уровень жалоб?', 'Оцените свою руку в повседневных и спортивных задачах', 30::smallint, TRUE),
  (5, 'sport_clearance_p5',      'Безболезненные контролируемые быстрые и спорт-специфичные движения; очный допуск куратора/врача (единого числового срока нет, диапазон 12–36 недель)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 40::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_biceps_tenodesis' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
